$LP="$env:TEMP\driver-install-$(Get-Date -Format 'yyyyMMdd-HHmmss').log";$RP="$env:TEMP\driver-report-$(Get-Date -Format 'yyyyMMdd-HHmmss').txt";$DP="$env:TEMP\driver-downloads";Write-Host "========================================" -ForegroundColor Cyan;Write-Host "  Universal Driver Installer Script" -ForegroundColor Cyan;Write-Host "========================================" -ForegroundColor Cyan;Write-Host "";if(-not([Security.Principal.WindowsPrincipal][Security.Principal.WindowsIdentity]::GetCurrent()).IsInRole([Security.Principal.WindowsBuiltInRole]"Administrator")){Write-Host "ERROR: Run PowerShell as Administrator!" -ForegroundColor Red;Read-Host "Press Enter to exit";exit 1};function WL{param([string]$M);$ts=Get-Date -Format "yyyy-MM-dd HH:mm:ss";Write-Host "[$ts] $M";Add-Content -Path $LP -Value "[$ts] $M" -EA SilentlyContinue};function AddReport{param([string]$M);Add-Content -Path $RP -Value $M -EA SilentlyContinue};WL "Script started";WL "Log file: $LP";WL "Report file: $RP";if(-not(Test-Path $DP)){New-Item -ItemType Directory -Path $DP -Force|Out-Null};AddReport "========================================";AddReport "DRIVER DETECTION REPORT";AddReport "Generated: $(Get-Date)";AddReport "========================================";AddReport "";$gpu=@();Write-Host "Detecting GPUs..." -ForegroundColor Yellow;Get-WmiObject Win32_VideoController -EA 0|Where-Object{$_.Name}|ForEach-Object{if($_.Name -like "*NVIDIA*"){$gpu+=@{Type="NVIDIA";Name=$_.Name};WL "Found NVIDIA: $($_.Name)"}if($_.Name -like "*AMD*" -or $_.Name -like "*Radeon*"){$gpu+=@{Type="AMD";Name=$_.Name};WL "Found AMD: $($_.Name)"}if($_.Name -like "*Intel*"){$gpu+=@{Type="Intel";Name=$_.Name};WL "Found Intel: $($_.Name)"}};$dev=@();Write-Host "Detecting motherboard devices..." -ForegroundColor Yellow;Get-WmiObject Win32_NetworkAdapterConfiguration -EA 0|Where-Object{$_.Description}|ForEach-Object{$dev+=@{Type="Network";Name=$_.Description};WL "Found Network: $($_.Description)"};Get-WmiObject Win32_SoundDevice -EA 0|Where-Object{$_.Name}|ForEach-Object{$dev+=@{Type="Audio";Name=$_.Name};WL "Found Audio: $($_.Name)"};Get-WmiObject Win32_IDEController -EA 0|Where-Object{$_.Name}|ForEach-Object{$dev+=@{Type="Storage";Name=$_.Name};WL "Found Storage: $($_.Name)"};Get-WmiObject Win32_USBController -EA 0|Where-Object{$_.Name}|ForEach-Object{$dev+=@{Type="USB";Name=$_.Name};WL "Found USB: $($_.Name)"};Get-WmiObject Win32_BaseBoard -EA 0|ForEach-Object{$dev+=@{Type="Motherboard";Name="$($_.Manufacturer) $($_.Product)"};WL "Found Motherboard: $($_.Manufacturer) $($_.Product)"};Write-Host "";Write-Host "========== DETECTED HARDWARE ==========" -ForegroundColor Green;Write-Host "GPUs found: $($gpu.Count)" -ForegroundColor Green;$gpu|ForEach-Object{Write-Host "  - $($_.Type): $($_.Name)" -ForegroundColor Green};AddReport "DETECTED HARDWARE";AddReport "================";AddReport "";AddReport "GPUs found: $($gpu.Count)";$gpu|ForEach-Object{AddReport "  - $($_.Type): $($_.Name)"};AddReport "";Write-Host "";Write-Host "Devices found: $($dev.Count)" -ForegroundColor Green;$dev|Select-Object -First 5|ForEach-Object{Write-Host "  - $($_.Type): $($_.Name)" -ForegroundColor Green};if($dev.Count -gt 5){Write-Host "  ... and $($dev.Count-5) more devices" -ForegroundColor Green};AddReport "System Devices found: $($dev.Count)";$dev|ForEach-Object{AddReport "  - $($_.Type): $($_.Name)"};AddReport "";Write-Host "";Write-Host "========== DOWNLOAD LINKS ==========" -ForegroundColor Green;AddReport "DOWNLOAD LINKS";AddReport "==============";AddReport "";if($gpu|Where-Object{$_.Type -eq "NVIDIA"}){Write-Host "";Write-Host "NVIDIA Drivers:" -ForegroundColor Cyan;Write-Host "https://www.nvidia.com/Download/index.aspx" -ForegroundColor White;AddReport "NVIDIA:";AddReport "  https://www.nvidia.com/Download/index.aspx";AddReport ""};if($gpu|Where-Object{$_.Type -eq "AMD"}){Write-Host "";Write-Host "AMD Drivers:" -ForegroundColor Cyan;Write-Host "https://www.amd.com/en/technologies/radeon-software" -ForegroundColor White;AddReport "AMD:";AddReport "  https://www.amd.com/en/technologies/radeon-software";AddReport ""};if($gpu|Where-Object{$_.Type -eq "Intel"}){Write-Host "";Write-Host "Intel Arc Drivers:" -ForegroundColor Cyan;Write-Host "https://www.intel.com/content/www/us/en/download/785597/intel-arc-graphics-driver.html" -ForegroundColor White;AddReport "Intel Arc:";AddReport "  https://www.intel.com/content/www/us/en/download/785597/intel-arc-graphics-driver.html";AddReport ""};$mb=Get-WmiObject Win32_BaseBoard -EA 0;if($mb){$mfg=$mb.Manufacturer.ToLower();Write-Host "";Write-Host "Chipset Drivers:" -ForegroundColor Cyan;AddReport "Chipset:";if($mfg -like "*intel*"){Write-Host "https://www.intel.com/content/www/us/en/download/17596/intel-chipset-device-software.html" -ForegroundColor White;AddReport "  https://www.intel.com/content/www/us/en/download/17596/intel-chipset-device-software.html"};if($mfg -like "*amd*"){Write-Host "https://www.amd.com/en/support" -ForegroundColor White;AddReport "  https://www.amd.com/en/support"};AddReport ""};Write-Host "";Write-Host "========== INSTRUCTIONS ==========" -ForegroundColor Cyan;Write-Host "1. Review the links above" -ForegroundColor Cyan;Write-Host "2. Download drivers from each link" -ForegroundColor Cyan;Write-Host "3. Run the installer executables" -ForegroundColor Cyan;Write-Host "4. Restart your computer" -ForegroundColor Cyan;Write-Host "";Write-Host "Report saved to: $RP" -ForegroundColor Yellow;Write-Host "Log file: $LP" -ForegroundColor Yellow;Write-Host "";AddReport "NEXT STEPS";AddReport "==========";AddReport "1. Copy the links above into your web browser";AddReport "2. Download drivers from each link";AddReport "3. Run the installer executables";AddReport "4. Restart your computer";WL "Script completed";AddReport "";AddReport "Script completed at $(Get-Date)";Write-Host "Opening report file..." -ForegroundColor Yellow;Start-Process notepad.exe $RP;Read-Host "Press Enter to exit"
